import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';

// Contexto de autenticación
import { AuthProvider } from './context/AuthContext';

// Componentes de estructura
import Layout          from './components/Layout';
import RutaProtegida   from './components/RutaProtegida';

// Páginas
import Login       from './pages/Login';
import Dashboard   from './pages/Dashboard';
import Usuarios    from './pages/Usuarios';
import Descuentos  from './pages/Descuentos';
import Convenios   from './pages/Convenios';
import Camaras     from './pages/Camaras';
import Vehiculos   from './pages/Vehiculos';
import Parqueadero from './pages/Parqueadero';

// CSS global de componentes
import './components/Layout.css';

/**
 * App.js — Punto de entrada del enrutador de AutoSlot.
 * Organiza rutas públicas (Login) y privadas (resto de módulos).
 * Las rutas privadas están protegidas por RutaProtegida.
 */
export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>

          {/* Ruta raíz: redirige al dashboard */}
          <Route path="/" element={<Navigate to="/dashboard" replace />} />

          {/* Ruta pública: Login */}
          <Route path="/login" element={<Login />} />

          {/* Rutas privadas: requieren autenticación */}
          <Route
            path="/"
            element={
              <RutaProtegida>
                <Layout />
              </RutaProtegida>
            }
          >
            <Route path="dashboard"    element={<Dashboard />} />
            <Route path="usuarios"     element={<Usuarios />} />
            <Route path="descuentos"   element={<Descuentos />} />
            <Route path="convenios"    element={<Convenios />} />
            <Route path="camaras"      element={<Camaras />} />
            <Route path="vehiculos"    element={<Vehiculos />} />
            <Route path="parqueadero"  element={<Parqueadero />} />
          </Route>

          {/* Ruta 404: redirige al dashboard */}
          <Route path="*" element={<Navigate to="/dashboard" replace />} />

        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
